import { writeFileSync } from "node:fs";
import { resolve } from "node:path";
import type { Options } from "@wdio/types";

const fixturePath = resolve("/tmp/toka-e2e-happy-path.mp4");
writeFileSync(
  fixturePath,
  Buffer.from(
    "",
    "base64",
  ),
);
process.env.TOKA_E2E_VIDEO = fixturePath;

const binaryPath = resolve(
  `src-tauri/target/debug/toka${process.platform === "win32" ? ".exe" : ""}`,
);

export const config: Options.Testrunner = {
  runner: "local",
  specs: ["./test/integration/happy-path.spec.ts"],
  maxInstances: 1,
  framework: "mocha",
  reporters: ["spec"],
  services: [["tauri", { appBinaryPath: binaryPath, driverProvider: "embedded" }]],
  capabilities: [
    {
      browserName: "tauri",
      "tauri:options": { application: binaryPath },
    },
  ],
  logLevel: "warn",
  waitforTimeout: 10_000,
  connectionRetryTimeout: 30_000,
  mochaOpts: { timeout: 30_000 },
};
